import { join, resolve } from "path";
import fs from "fs";

export class CardImageResolver {
  private static getBaseDir(): string {
    const distAssets = join(__dirname, "assets/cards");

    const srcAssets = join(__dirname, "../../assets/cards");

    if (fs.existsSync(distAssets)) {
      return distAssets;
    }

    return srcAssets;
  }

  static getAbsolutePath(color: string, value: string): string {
    const filename = this.formatFilename(color, value);
    return join(this.getBaseDir(), filename);
  }

  static getRelativePath(color: string, value: string): string {
    return `assets/cards/${this.formatFilename(color, value)}`;
  }

  static getCwdRelativePath(color: string, value: string): string {
    return `dist/${this.getRelativePath(color, value)}`;
  }

  static getUrl(color: string, value: string, baseUrl = "/"): string {
    return `${baseUrl}${this.getRelativePath(color, value)}`;
  }

  static getFilename(color: string, value: string): string {
    return this.formatFilename(color, value);
  }

  private static formatFilename(color: string, value: string): string {
    const normalizedColor = color.toLowerCase();
    const normalizedValue = value.toLowerCase().replace(" ", "_");

    if (color === "Especial") {
      return `${normalizedValue}.png`;
    }
    return `${normalizedColor}_${normalizedValue}.png`;
  }

  static listImages(): string[] {
    try {
      const dir = this.getBaseDir();
      return fs
        .readdirSync(dir)
        .filter((f) => f.endsWith(".png"))
        .sort();
    } catch {
      return [];
    }
  }
}
