import fs from "fs";
import { join } from "path";
import { GameEngine } from "../core/GameEngine.js";
import type {
  SavedGameState,
  GameIndex,
  GameIndexEntry,
} from "../types/index.js";

export interface GameInfo {
  gameId: string;
  playerCount: number;
  playerNames: string[];
  currentPlayer: string;
  turnNumber: number;
  gameOver: boolean;
  winner: string | null;
  createdAt: Date;
  updatedAt: Date;
}

export class GameStorage {
  private storageDir: string;
  private indexPath: string;

  constructor(dirPath: string = "uno_games_data") {
    this.storageDir = join(process.cwd(), dirPath);
    this.indexPath = join(this.storageDir, "index.json");

    this.initDatabase();
  }

  private initDatabase(): void {
    try {
      if (!fs.existsSync(this.storageDir)) {
        fs.mkdirSync(this.storageDir, { recursive: true });
      }

      if (!fs.existsSync(this.indexPath)) {
        const initialIndex: GameIndex = { games: {} };
        fs.writeFileSync(
          this.indexPath,
          JSON.stringify(initialIndex, null, 2),
          "utf-8",
        );
      }
    } catch (error) {}
  }

  private readIndex(): GameIndex {
    try {
      const data = fs.readFileSync(this.indexPath, "utf-8");
      return JSON.parse(data);
    } catch (error) {
      return { games: {} };
    }
  }

  private writeIndex(index: GameIndex): void {
    try {
      fs.writeFileSync(this.indexPath, JSON.stringify(index, null, 2), "utf-8");
    } catch (error) {}
  }

  private getGameFilePath(gameId: string): string {
    return join(this.storageDir, `${gameId}.json`);
  }

  saveGame(gameId: string, game: GameEngine): void {
    const state = game.toSavedState();
    const now = Date.now();

    const filePath = this.getGameFilePath(gameId);
    try {
      fs.writeFileSync(filePath, JSON.stringify(state, null, 2), "utf-8");
    } catch (error) {
      return;
    }

    const index = this.readIndex();
    const isNew = !index.games[gameId];

    index.games[gameId] = {
      gameId,
      playerCount: state.players.length,
      playerNames: state.players.map((p) => p.name),
      currentPlayer: state.players[state.currentPlayerIdx].name,
      turnNumber: state.turnNumber,
      gameOver: state.gameOver,
      winner: state.winner,
      createdAt: isNew ? now : index.games[gameId].createdAt,
      updatedAt: now,
    };

    this.writeIndex(index);
  }

  loadGame(gameId: string): GameEngine | null {
    const filePath = this.getGameFilePath(gameId);
    if (!fs.existsSync(filePath)) {
      return null;
    }

    try {
      const fileContent = fs.readFileSync(filePath, "utf-8");
      const savedState: SavedGameState = JSON.parse(fileContent);
      return new GameEngine(undefined, savedState);
    } catch (error) {
      return null;
    }
  }

  gameExists(gameId: string): boolean {
    const index = this.readIndex();
    return !!index.games[gameId];
  }

  deleteGame(gameId: string): boolean {
    const filePath = this.getGameFilePath(gameId);
    let deleted = false;

    if (fs.existsSync(filePath)) {
      fs.unlinkSync(filePath);
      deleted = true;
    }

    const index = this.readIndex();
    if (index.games[gameId]) {
      delete index.games[gameId];
      this.writeIndex(index);
      deleted = true;
    }

    return deleted;
  }

  deleteGames(gameIds: string[]): number {
    if (gameIds.length === 0) return 0;

    const index = this.readIndex();
    let count = 0;

    for (const gameId of gameIds) {
      const filePath = this.getGameFilePath(gameId);
      if (fs.existsSync(filePath)) {
        fs.unlinkSync(filePath);
      }
      if (index.games[gameId]) {
        delete index.games[gameId];
        count++;
      }
    }

    if (count > 0) this.writeIndex(index);
    return count;
  }

  clearAllGames(): number {
    const index = this.readIndex();
    const gameIds = Object.keys(index.games);
    const count = this.deleteGames(gameIds);
    return count;
  }

  clearFinishedGames(): number {
    const index = this.readIndex();
    const finishedGameIds = Object.values(index.games)
      .filter((info) => info.gameOver)
      .map((info) => info.gameId);

    return this.deleteGames(finishedGameIds);
  }

  clearOldGames(olderThanDays: number): number {
    const cutoffTime = Date.now() - olderThanDays * 24 * 60 * 60 * 1000;
    const index = this.readIndex();

    const oldGameIds = Object.values(index.games)
      .filter((info) => info.updatedAt < cutoffTime)
      .map((info) => info.gameId);

    return this.deleteGames(oldGameIds);
  }

  listGames(): string[] {
    const index = this.readIndex();
    return Object.values(index.games)
      .sort((a, b) => b.updatedAt - a.updatedAt)
      .map((entry) => entry.gameId);
  }

  listGamesFiltered(options?: {
    onlyActive?: boolean;
    onlyFinished?: boolean;
    limit?: number;
  }): string[] {
    const index = this.readIndex();
    let entries = Object.values(index.games);

    if (options?.onlyActive) {
      entries = entries.filter((e) => !e.gameOver);
    } else if (options?.onlyFinished) {
      entries = entries.filter((e) => e.gameOver);
    }

    entries.sort((a, b) => b.updatedAt - a.updatedAt);

    if (options?.limit) {
      entries = entries.slice(0, options.limit);
    }

    return entries.map((e) => e.gameId);
  }

  getGameInfo(
    gameId: string,
  ): { gameId: string; createdAt: Date; updatedAt: Date } | null {
    const index = this.readIndex();
    const entry = index.games[gameId];

    if (!entry) return null;

    return {
      gameId: entry.gameId,
      createdAt: new Date(entry.createdAt),
      updatedAt: new Date(entry.updatedAt),
    };
  }

  getDetailedGameInfo(gameId: string): GameInfo | null {
    const index = this.readIndex();
    const entry = index.games[gameId];

    if (!entry) return null;

    return {
      ...entry,
      createdAt: new Date(entry.createdAt),
      updatedAt: new Date(entry.updatedAt),
    };
  }

  getStats(): {
    totalGames: number;
    activeGames: number;
    finishedGames: number;
    oldestGame: Date | null;
    newestGame: Date | null;
  } {
    const index = this.readIndex();
    const entries = Object.values(index.games);

    let activeCount = 0;
    let finishedCount = 0;
    let oldest = Infinity;
    let newest = 0;

    for (const entry of entries) {
      if (entry.gameOver) finishedCount++;
      else activeCount++;

      if (entry.createdAt < oldest) oldest = entry.createdAt;
      if (entry.createdAt > newest) newest = entry.createdAt;
    }

    return {
      totalGames: entries.length,
      activeGames: activeCount,
      finishedGames: finishedCount,
      oldestGame: oldest === Infinity ? null : new Date(oldest),
      newestGame: newest === 0 ? null : new Date(newest),
    };
  }

  exportGame(gameId: string): string | null {
    const index = this.readIndex();
    const entry = index.games[gameId];
    const filePath = this.getGameFilePath(gameId);

    if (!entry || !fs.existsSync(filePath)) return null;

    const fileContent = fs.readFileSync(filePath, "utf-8");
    const state = JSON.parse(fileContent);

    return JSON.stringify(
      {
        gameId,
        createdAt: entry.createdAt,
        updatedAt: entry.updatedAt,
        state,
      },
      null,
      2,
    );
  }

  importGame(jsonData: string): boolean {
    try {
      const data = JSON.parse(jsonData);
      const filePath = this.getGameFilePath(data.gameId);

      fs.writeFileSync(filePath, JSON.stringify(data.state, null, 2), "utf-8");

      const index = this.readIndex();
      index.games[data.gameId] = {
        gameId: data.gameId,
        playerCount: data.state.players.length,
        playerNames: data.state.players.map((p: any) => p.name),
        currentPlayer: data.state.players[data.state.currentPlayerIdx].name,
        turnNumber: data.state.turnNumber,
        gameOver: data.state.gameOver,
        winner: data.state.winner,
        createdAt: data.createdAt,
        updatedAt: data.updatedAt,
      };

      this.writeIndex(index);
      return true;
    } catch {
      return false;
    }
  }

  close(): void {}
}
