import type { CardColor } from "../types/index.js";
import { Card } from "./Card.js";
import { Deck } from "./Deck.js";

export abstract class Player {
  readonly name: string;
  hand: Card[];

  constructor(name: string, hand: Card[] = []) {
    this.name = name;
    this.hand = hand;
  }

  drawCard(deck: Deck, quantity: number = 1): void {
    for (let i = 0; i < quantity; i++) {
      const card = deck.drawCard();
      if (card) {
        this.hand.push(card);
      }
    }
  }

  removeCard(cardIndex: number): Card | null {
    if (cardIndex < 0 || cardIndex >= this.hand.length) {
      return null;
    }
    return this.hand.splice(cardIndex, 1)[0];
  }

  isUno(): boolean {
    return this.hand.length === 1;
  }

  hasWon(): boolean {
    return this.hand.length === 0;
  }

  abstract chooseColor(): CardColor;

  abstract chooseMove(
    topCard: Card,
    currentColor: CardColor,
    players: Player[],
    currentPlayerIdx: number,
    direction: number,
  ): Card | "draw";
}
