import type {
  CardColor,
  GameDirection,
  GameOptions,
  GameState,
  PlayData,
  SavedGameState,
  SavedPlayerState,
  TurnLog,
  PlayerInfo,
} from "../types/index.js";
import { Card } from "./Card.js";
import { Deck } from "./Deck.js";
import { Player } from "./Player.js";
import { HumanPlayer } from "./HumanPlayer.js";
import { AIPlayer } from "./AIPlayer.js";
import { i18n, parseColor } from "../i18n/index.js";
import { randomUUID } from "crypto";

interface TurnResult {
  success: boolean;
  log?: TurnLog[];
  error?: string;
}

export class GameEngine {
  gameId!: string;
  id!: string;
  players!: Player[];
  deck!: Deck;
  discardPile!: Card[];
  currentPlayerIdx!: number;
  direction!: GameDirection;
  currentColor!: CardColor;
  gameOver!: boolean;
  winner!: Player | null;
  turnNumber!: number;

  constructor(options?: GameOptions, savedState?: SavedGameState) {
    if (savedState) {
      this.id = savedState.gameId || randomUUID();
      this.rebuildFromState(savedState);
    } else if (options) {
      this.id = randomUUID();

      if (!options.players || options.players.length === 0) {
        throw new Error(i18n.t("errors.playerRequired"));
      }

      if (options.language) {
        i18n.setLanguage(options.language);
      }

      this.players = options.players.map((p) =>
        p.type === "HUMAN" ? new HumanPlayer(p.name) : new AIPlayer(p.name),
      );

      this.deck = new Deck();
      this.discardPile = [];
      this.currentPlayerIdx = 0;
      this.direction = 1;
      this.currentColor = "Vermelho";
      this.gameOver = false;
      this.winner = null;
      this.turnNumber = 1;

      this.dealInitialCards();
      this.startDiscardPile();
    } else {
      throw new Error("GameEngine requires options or savedState");
    }
  }

  private rebuildFromState(state: SavedGameState): void {
    const strToCard = (s: string): Card => Card.fromString(s);

    this.deck = new Deck();
    this.deck.setCards(state.deck.map(strToCard));

    this.discardPile = state.discardPile.map(strToCard);

    this.players = state.players.map((p: SavedPlayerState) => {
      const hand = p.hand.map(strToCard);
      if (p.type === "JogadorHumano" || p.type === "HUMAN") {
        return new HumanPlayer(p.name, hand);
      }
      return new AIPlayer(p.name, hand);
    });

    this.currentPlayerIdx = state.currentPlayerIdx;
    this.direction = state.direction;
    this.currentColor = state.currentColor;
    this.turnNumber = state.turnNumber;
    this.gameOver = state.gameOver;
    this.winner = state.winner
      ? (this.players.find((p) => p.name === state.winner) ?? null)
      : null;
  }

  private dealInitialCards(): void {
    for (const player of this.players) {
      for (let i = 0; i < 7; i++) {
        player.drawCard(this.deck, 1);
      }
    }
  }

  private startDiscardPile(): void {
    let initialCard = this.deck.drawCard();
    if (!initialCard) {
      throw new Error(i18n.t("errors.emptyDeck"));
    }

    while (initialCard.color === "Especial") {
      const tmp = initialCard;
      this.deck.getCards().push(tmp);
      this.deck.shuffle();
      initialCard = this.deck.drawCard();
      if (!initialCard) {
        throw new Error(i18n.t("errors.emptyDeck"));
      }
    }

    this.discardPile.push(initialCard);
    this.currentColor = initialCard.color;
  }

  private nextPlayer(): void {
    this.currentPlayerIdx =
      (this.currentPlayerIdx + this.direction + this.players.length) %
      this.players.length;

    if (this.currentPlayerIdx === 0) {
      this.turnNumber += 1;
    }
  }

  private isValidMove(card: Card): boolean {
    const topCard = this.discardPile[this.discardPile.length - 1];

    return (
      card.color === this.currentColor ||
      card.value === topCard.value ||
      card.color === "Especial"
    );
  }

  private applyCardEffect(
    player: Player,
    card: Card,
    moveData: PlayData | null,
  ): { effectLog: string | null; skipNext: boolean } {
    let skipNext = false;
    let effectLog: string | null = null;

    if (card.value === "Pular") {
      skipNext = true;
    } else if (card.value === "Inverter") {
      this.direction = (this.direction * -1) as GameDirection;
    }

    let drawCount = 0;
    if (card.value === "+2") {
      skipNext = true;
      drawCount = 2;
    } else if (card.value === "Curinga +4") {
      skipNext = true;
      drawCount = 4;
    }

    if (drawCount > 0) {
      const nextIdx =
        (this.currentPlayerIdx + this.direction + this.players.length) %
        this.players.length;
      const nextPlayer = this.players[nextIdx];
      nextPlayer.drawCard(this.deck, drawCount);
    }

    if (card.color === "Especial") {
      let newColor: CardColor | undefined;

      if (player instanceof HumanPlayer) {
        if (moveData && moveData.chosenColor) {
          const parsed = parseColor(moveData.chosenColor);
          newColor = parsed || (moveData.chosenColor as CardColor);
        } else {
          newColor = "Vermelho";
        }
      } else {
        newColor = (player as AIPlayer).chooseColor();
      }

      this.currentColor = newColor!;
    } else {
      this.currentColor = card.color;
    }

    return { effectLog, skipNext };
  }

  processHumanTurn(playerName: string, data: PlayData): TurnResult {
    const currentPlayer = this.players[this.currentPlayerIdx];

    if (
      !(currentPlayer instanceof HumanPlayer) ||
      currentPlayer.name !== playerName
    ) {
      return {
        success: false,
        error: i18n.t("errors.notYourTurn"),
      };
    }

    const logs: TurnLog[] = [];

    if (data.action === "draw_card") {
      if (this.deck.cardsRemaining() === 0) {
        const ok = this.deck.refill(this.discardPile);
        if (!ok) {
          return {
            success: false,
            error: i18n.t("errors.notEnoughCardsToRefill"),
          };
        }
      }

      currentPlayer.drawCard(this.deck, 1);

      logs.push({
        player: currentPlayer.name,
        action: "DRAW_CARD" as const,
        quantity: 1,
      });

      this.nextPlayer();
      return { success: true, log: logs };
    }

    if (data.action === "play_card") {
      const idx = data.cardIndex;
      if (idx === undefined || idx < 0 || idx >= currentPlayer.hand.length) {
        return {
          success: false,
          error: i18n.t("errors.invalidCardIndex"),
        };
      }

      const card = currentPlayer.hand[idx];

      if (!this.isValidMove(card)) {
        return {
          success: false,
          error: i18n.t("errors.invalidMove"),
        };
      }

      if (card.color === "Especial") {
        if (!data.chosenColor) {
          return {
            success: false,
            error: i18n.t("errors.colorRequired"),
          };
        }

        const parsedColor = parseColor(data.chosenColor);

        if (!parsedColor) {
          return {
            success: false,
            error: i18n.t("errors.invalidColor", { color: data.chosenColor }),
          };
        }

        data.chosenColor = parsedColor;
      }

      currentPlayer.removeCard(idx);
      this.discardPile.push(card);

      const log: TurnLog = {
        player: currentPlayer.name,
        action: "PLAY_CARD" as const,
        card: card.toString(),
      };

      if (currentPlayer.hasWon()) {
        this.gameOver = true;
        this.winner = currentPlayer;
        logs.push(log);
        return { success: true, log: logs };
      }

      this.applyCardEffect(currentPlayer, card, data);

      logs.push(log);
      this.nextPlayer();
      return { success: true, log: logs };
    }

    return {
      success: false,
      error: i18n.t("errors.invalidMove"),
    };
  }

  processAITurn(): TurnLog | null {
    if (this.gameOver) return null;

    const currentPlayer = this.players[this.currentPlayerIdx];
    if (!(currentPlayer instanceof AIPlayer)) {
      return null;
    }

    if (this.deck.cardsRemaining() === 0) {
      this.deck.refill(this.discardPile);
    }

    const topCard = this.discardPile[this.discardPile.length - 1];
    const move = currentPlayer.chooseMove(
      topCard,
      this.currentColor,
      this.players,
      this.currentPlayerIdx,
      this.direction,
    );

    if (move === "draw") {
      currentPlayer.drawCard(this.deck, 1);
      const log: TurnLog = {
        player: currentPlayer.name,
        action: "DRAW_CARD",
        quantity: 1,
      };
      this.nextPlayer();
      return log;
    }

    const card = move;
    const idx = currentPlayer.hand.findIndex((c) => c === card);
    if (idx >= 0) {
      currentPlayer.removeCard(idx);
    }
    this.discardPile.push(card);

    const log: TurnLog = {
      player: currentPlayer.name,
      action: "PLAY_CARD",
      card: card.toString(),
    };

    if (currentPlayer.hasWon()) {
      this.gameOver = true;
      this.winner = currentPlayer;
      return log;
    }

    this.applyCardEffect(currentPlayer, card, null);

    this.nextPlayer();
    return log;
  }

  getState(turnLog: TurnLog[] = []): GameState {
    const nextIdx =
      (this.currentPlayerIdx + this.direction + this.players.length) %
      this.players.length;
    const nextPlayer = this.players[nextIdx];

    const order: string[] = [];
    let idx = this.currentPlayerIdx;
    for (let i = 0; i < this.players.length; i++) {
      order.push(this.players[idx].name);
      idx = (idx + this.direction + this.players.length) % this.players.length;
    }

    const topCard = this.discardPile[this.discardPile.length - 1];

    return {
      gameId: this.id,
      turnLog,
      turnNumber: this.turnNumber,
      gameOver: this.gameOver,
      winner: this.winner ? this.winner.name : null,
      currentPlayer: this.players[this.currentPlayerIdx].name,
      nextPlayer: nextPlayer.name,
      playerOrder: order,
      currentColor: this.currentColor,
      topCard: topCard.toJSON(),
      deckCardsRemaining: this.deck.cardsRemaining(),
      players: this.players.map((p, playerIndex) => {
        const base: PlayerInfo = {
          name: p.name,
          cardsInHand: p.hand.length,
          isUno: p.isUno(),
        };

        if (p instanceof HumanPlayer && playerIndex === this.currentPlayerIdx) {
          const hand = p.hand.map((c) => c.toJSON());
          const validMoves: number[] = [];

          for (let i = 0; i < p.hand.length; i++) {
            const card = p.hand[i];
            if (this.isValidMove(card)) {
              validMoves.push(i);
            }
          }

          return {
            ...base,
            hand,
            validMoves,
          } as PlayerInfo;
        }

        return base;
      }),
    };
  }

  toSavedState(): SavedGameState {
    return {
      gameId: this.id,
      players: this.players.map((p) => ({
        name: p.name,
        type: p instanceof HumanPlayer ? "JogadorHumano" : "JogadorIAReativa",
        hand: p.hand.map((c) => c.toString()),
      })),
      discardPile: this.discardPile.map((c) => c.toString()),
      deck: this.deck.getCards().map((c) => c.toString()),
      currentPlayerIdx: this.currentPlayerIdx,
      direction: this.direction,
      currentColor: this.currentColor,
      turnNumber: this.turnNumber,
      gameOver: this.gameOver,
      winner: this.winner ? this.winner.name : null,
    };
  }
}
