import type { CardColor, CardValue, SerializedCard } from "../types/index.js";
import { i18n } from "../i18n/index.js";
import { CardImageResolver } from "../utils/assets.js";

export class Card {
  readonly color: CardColor;
  readonly value: CardValue;

  constructor(color: CardColor, value: CardValue) {
    this.validateCard(color, value);
    this.color = color;
    this.value = value;
  }

  toString(): string {
    if (this.color === "Especial") {
      return i18n.getCardValue(this.value);
    }
    return `${i18n.getCardValue(this.value)} ${i18n.getCardColor(this.color)}`;
  }

  getImageFilename(): string {
    const normalizedColor = this.color.toLowerCase();
    const normalizedValue = this.value.toLowerCase().replace(" ", "_");

    if (this.color === "Especial") {
      return `${normalizedValue}.png`;
    }
    return `${normalizedColor}_${normalizedValue}.png`;
  }

  toJSON(): SerializedCard {
    return {
      color: this.color,
      value: this.value,
      display: this.toString(),
      imageFilename: this.getImageFilename(),
      imageAbsolutePath: CardImageResolver.getAbsolutePath(
        this.color,
        this.value,
      ),
      imageRelativePath: CardImageResolver.getRelativePath(
        this.color,
        this.value,
      ),
      imageCwdPath: CardImageResolver.getCwdRelativePath(
        this.color,
        this.value,
      ),
    };
  }

  private validateCard(color: CardColor, value: CardValue): void {
    const validColors: CardColor[] = [
      "Vermelho",
      "Amarelo",
      "Verde",
      "Azul",
      "Especial",
    ];

    if (!validColors.includes(color)) {
      throw new Error(i18n.t("errors.invalidColor", { color }));
    }

    if (
      (value === "Curinga" || value === "Curinga +4") &&
      color !== "Especial"
    ) {
      throw new Error(i18n.t("errors.invalidValue", { value }));
    }
  }

  static fromString(str: string): Card {
    if (str === "Curinga" || str === "Curinga +4") {
      return new Card("Especial", str as CardValue);
    }

    const parts = str.split(" ");
    const value = parts[0] as CardValue;
    const color = parts[1] as CardColor;

    return new Card(color, value);
  }
}
