export class I18n {
  private currentLanguage: Language = "pt-BR";

  setLanguage(language: Language): void {
    this.currentLanguage = language;
  }

  getLanguage(): Language {
    return this.currentLanguage;
  }

  getCardColor(cardColor: CardColor): string {
    return this.t(`cards.colors.${cardColor}`);
  }

  getCardValue(cardValue: CardValue): string {
    return this.t(`cards.values.${cardValue}`);
  }

  parseColor(input: string): CardColor | null {
    const lower = input.toLowerCase().trim();
    return messages[this.currentLanguage].cards.inputColors[lower] || null;
  }

  parseValue(input: string): CardValue | null {
    const lower = input.toLowerCase().trim();
    return messages[this.currentLanguage].cards.inputValues[lower] || null;
  }

  t(key: string, params?: Record<string, string | number>): string {
    const keys = key.split(".");
    let value: any = messages[this.currentLanguage];

    for (const k of keys) {
      value = value?.[k];
    }

    if (typeof value !== "string") {
      return key;
    }

    if (params) {
      return value.replace(/\{(\w+)\}/g, (_, k) => String(params[k] ?? ""));
    }

    return value;
  }
}

export const i18n = new I18n();

export function getCardDisplay(
  cardColor: CardColor,
  cardValue: CardValue,
): string {
  return i18n.getCardColor(cardColor) + " " + i18n.getCardValue(cardValue);
}

export function parseColor(input: string): CardColor | null {
  return i18n.parseColor(input);
}

export function parseValue(input: string): CardValue | null {
  return i18n.parseValue(input);
}
