import type { CardColor } from "../types/index.js";
import { Card } from "./Card.js";
import { Player } from "./Player.js";

export class AIPlayer extends Player {
  chooseColor(): CardColor {
    const colorsInHand = this.hand
      .filter((card) => card.color !== "Especial")
      .map((card) => card.color);

    if (colorsInHand.length === 0) {
      const colors: CardColor[] = ["Vermelho", "Amarelo", "Verde", "Azul"];
      return colors[Math.floor(Math.random() * colors.length)];
    }

    const colorCounts = colorsInHand.reduce(
      (acc, color) => {
        acc[color] = (acc[color] || 0) + 1;
        return acc;
      },
      {} as Record<string, number>,
    );

    return Object.keys(colorCounts).reduce((a, b) =>
      colorCounts[a] > colorCounts[b] ? a : b,
    ) as CardColor;
  }

  chooseMove(
    topCard: Card,
    currentColor: CardColor,
    players: Player[],
    currentPlayerIdx: number,
    direction: number,
  ): Card | "draw" {
    const validMoves = this.hand.filter(
      (card) =>
        card.color === currentColor ||
        card.value === topCard.value ||
        card.color === "Especial",
    );

    if (validMoves.length === 0) {
      return "draw";
    }

    const nextPlayerIdx = (currentPlayerIdx + direction) % players.length;
    const nextPlayer = players[nextPlayerIdx];

    if (nextPlayer.hand.length === 1) {
      const attackMoves = validMoves.filter(
        (card) =>
          card.value === "+2" ||
          card.value === "Pular" ||
          card.value === "Curinga +4",
      );
      if (attackMoves.length > 0) {
        return attackMoves[Math.floor(Math.random() * attackMoves.length)];
      }
    }

    const wildcardMoves = validMoves.filter(
      (card) => card.color === "Especial",
    );
    if (wildcardMoves.length > 0) {
      const coloredMoves = validMoves.filter(
        (card) => card.color === currentColor,
      );
      if (coloredMoves.length === 0) {
        return wildcardMoves[Math.floor(Math.random() * wildcardMoves.length)];
      }
    }

    const actionMoves = validMoves.filter(
      (card) =>
        card.value === "+2" ||
        card.value === "Pular" ||
        card.value === "Inverter",
    );
    if (actionMoves.length > 0) {
      return actionMoves[Math.floor(Math.random() * actionMoves.length)];
    }

    const numericMoves = validMoves.filter((card) => /^\d$/.test(card.value));
    if (numericMoves.length > 0) {
      numericMoves.sort((a, b) => parseInt(b.value) - parseInt(a.value));
      return numericMoves[0];
    }

    return validMoves[0];
  }
}
